message:
style(test): use fold+write for hex_encode reference string

test_hex_encode_all_bytes_produces_valid_hex builds a 512-char
reference string by mapping each byte through format!("{b:02x}")
and collecting. Clippy's format_collect flags the per-iteration
String allocation as wasteful; the preferred pattern accumulates
via fold() into a single String with write!(). Change:

- let reference: String = bytes.iter().map(|b| format!("{b:02x}")).collect();
+ let reference: String = bytes.iter().fold(String::new(), |mut acc, b| {
+     use std::fmt::Write;
+     write!(acc, "{b:02x}").unwrap();
+     acc
+ });

Output unchanged (identical 512-char lowercase hex string); only the
allocation pattern changes.

files.patch:
@@ -371,7 +371,11 @@ mod tests {
         let bytes: Vec<u8> = (0..=255).collect();
         let hex = hex_encode(&bytes);
         assert_eq!(hex.len(), 512);
-        let reference: String = bytes.iter().map(|b| format!("{b:02x}")).collect();
+        let reference: String = bytes.iter().fold(String::new(), |mut acc, b| {
+            use std::fmt::Write;
+            write!(acc, "{b:02x}").unwrap();
+            acc
+        });
         assert_eq!(hex, reference);
     }
